export function docReady(body: () => void) {
  document.addEventListener("DOMContentLoaded", body)
}

export function throttle(f: (...args: any[]) => void, time: number) {
  let lastTime: null | number = null
  return function (this: any) {
    const current = Date.now()
    if (lastTime !== null && current - lastTime < time) return
    lastTime = current
    return f.call(this, arguments)
  }
}

export function h(
  tagName: string,
  classes?: string[],
  children?: string | HTMLElement | null,
  ...rest: (HTMLElement | null)[]
): HTMLElement & {
  on: (eventName: string, callback: (...args: any[]) => any) => HTMLElement
} {
  const $el = document.createElement(tagName) as ReturnType<typeof h>
  if (classes) $el.classList.add(...classes)
  if (typeof children === "string") $el.innerHTML = children
  else if (children instanceof HTMLElement) $el.append(children)
  $el.append(...(rest.filter((x) => x instanceof HTMLElement) as HTMLElement[]))
  $el.on = (eventName, callback) => {
    $el.addEventListener(eventName, callback)
    return $el
  }
  return $el
}
